export class BotCommandContext {
    /** @private **/
    constructor(_client, msg) {
        this._client = _client;
        this.msg = msg;
        this.say = async (message) => await this._client.say(this.msg.params.target, message);
        this.user = msg.userInfo.userName;
        this.channel = msg.params.target;
    }
}
